169	func (m *Manager) setupNative(h *host.Host, rc config.RunnerConfig) error {
170		version, err := m.GitHub.GetLatestRunnerVersion()
171		if err != nil {
172			return err
173		}
174	
175		ghArch := archForGitHub(h.Arch)
176		url := runnerTarballURL(version, h.OS, ghArch)
177		if url == "" {
178			return fmt.Errorf("unsupported OS/arch: %s/%s", h.OS, h.Arch)
179		}
180	
181		for _, name := range rc.InstanceNames() {
182			dir := h.RunnerDir(name)
183	
184			installed, _ := NativeRunnerConfigPresent(h, name)
185			if installed {
186				fmt.Fprintf(m.out(), "  %s: already installed, skipping\n", name)
187				continue
188			}
189	
190			fmt.Fprintf(m.out(), "  %s: installing runner v%s...\n", name, version)
191	
192			if h.OS == "linux" {
193				installDepsCmd := linuxElevatePrelude + `
194					if ! command -v curl >/dev/null 2>&1 || ! command -v tar >/dev/null 2>&1; then
195						if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl tar;
196						elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl tar;
197						elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl tar;
198						fi
199					fi
200				`
201				if _, err := h.Run(installDepsCmd); err != nil {
202					fmt.Fprintf(m.out(), "  %s: warning: failed to ensure curl/tar are installed: %v\n", name, err)
203				}
204			}
205	
206			if h.OS == "windows" {
207				fmt.Fprintf(m.out(), "  %s: downloading runner package...\n", name)
208				if _, err := h.RunShell(windowsNativeInstallScript(h, name, version, url)); err != nil {
209					return fmt.Errorf("installing runner on Windows: %w", err)
210				}
211			} else {
212				tarball := fmt.Sprintf("%s/ghsr-runner-%s-%s.tar.gz", h.TempDir(), name, version)
213				fmt.Fprintf(m.out(), "  %s: downloading runner v%s...\n", name, version)
214				if _, err := h.Run(fmt.Sprintf("mkdir -p %s", dir)); err != nil {
215					return fmt.Errorf("creating runner directory: %w", err)
216				}
217				cmds := fmt.Sprintf(
218					"cd %s && tarball=%s && rm -f \"$tarball\" && "+
219						"curl -fSL --retry 3 --retry-delay 2 -o \"$tarball\" '%s'",
220					dir, tarball, url,
221				)
222				if _, err := h.Run(cmds); err != nil {
223					return fmt.Errorf("downloading runner: %w", err)
224				}
225				fmt.Fprintf(m.out(), "  %s: extracting runner...\n", name)
226				cmds = fmt.Sprintf("cd %s && tarball=%s && tar xzf \"$tarball\" && rm -f \"$tarball\"", dir, tarball)
227				if _, err := h.Run(cmds); err != nil {
228					return fmt.Errorf("extracting runner: %w", err)
229				}
230			}
231	
232			if h.OS == "linux" {
233				fmt.Fprintf(m.out(), "  %s: installing runner dependencies...\n", name)
234				depsCmd := fmt.Sprintf(
235					"cd %s && %s && $SUDO ./bin/installdependencies.sh",
236					dir, strings.TrimSpace(linuxElevatePrelude),
237				)
238				if _, err := h.Run(depsCmd); err != nil {
239					fmt.Fprintf(m.out(), "  %s: warning: failed to install runner dependencies: %v\n", name, err)
240				}
241			}
242	
243			regToken, err := m.GitHub.GetRegistrationTokenScoped(rc.Scope(), rc.ScopeTarget())
244			if err != nil {
245				return err
246			}
247	
248			labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
249	
250			fmt.Fprintf(m.out(), "  %s: registering runner with GitHub...\n", name)
251			if h.OS == "windows" {
252				if _, err := h.RunShell(windowsNativeConfigScript(h, rc, name, regToken)); err != nil {
253					return fmt.Errorf("configuring runner on Windows: %w", err)
254				}
255			} else {
256				configURL := nativeConfigURL(rc)
257				configCmd := fmt.Sprintf(
258					"cd %s && ./config.sh --unattended --url '%s' --token '%s' --name '%s' --labels '%s' --work '_work' --replace",
259					dir, configURL, regToken, name, labels,
260				)
261				if rc.Group != "" {
262					configCmd += fmt.Sprintf(" --runnergroup '%s'", rc.Group)
263				}
264				if rc.Ephemeral {
265					configCmd += " --ephemeral"
266				}
267				if _, err := h.Run(configCmd); err != nil {
268					return fmt.Errorf("configuring runner: %w", err)
269				}
270			}
271	
272			fmt.Fprintf(m.out(), "  %s: configured\n", name)
273		}
274	
275		// For agentic runners, install gh-aw CLI on the host.
276		// gh-aw (GitHub Agentic Workflows) uses Docker on the host for AWF sandbox containers.
277		if rc.IsAgentic() && h.OS == "linux" {
278			fmt.Fprintf(m.out(), "  %s: installing gh-aw CLI for agentic profile...\n", rc.Name)
279			installGHAWCmd := `if [ -d ~/.local/share/gh/extensions/gh-aw ]; then
280				echo "gh-aw already installed"
281			else
282				curl -sL https://raw.githubusercontent.com/github/gh-aw/main/install-gh-aw.sh | bash
283			fi`
284			out, err := h.Run(installGHAWCmd)
285			if err != nil {
286				fmt.Fprintf(m.out(), "  %s: warning: failed to install gh-aw CLI: %v\n", rc.Name, err)
287			} else {
288				fmt.Fprintf(m.out(), "  %s: gh-aw CLI installed\n", rc.Name)
289				if out != "" {
290					fmt.Fprintf(m.out(), "  %s: gh-aw: %s\n", rc.Name, strings.TrimSpace(out))
291				}
292			}
293	
294			// Set up /opt/hostedtoolcache for gh-aw agent containers.
295			// gh-aw searches for tools (e.g., claude) in /opt/hostedtoolcache, which exists on
296			// GitHub Hosted Runners but not on self-hosted runners. We create a bind mount so
297			// agent containers can find npm-installed tools.
298			fmt.Fprintf(m.out(), "  %s: setting up /opt/hostedtoolcache for agentic workflows...\n", rc.Name)
299			npmPrefixCmd := `npm config get prefix 2>/dev/null || echo "/usr/local"`
300			npmPrefix, err := h.Run(npmPrefixCmd)
301			if err != nil {
302				fmt.Fprintf(m.out(), "  %s: warning: failed to detect npm prefix: %v\n", rc.Name, err)
303			} else {
304				npmPrefix = strings.TrimSpace(npmPrefix)
305				hostedtoolcacheSetup := fmt.Sprintf(`%s
306				if [ -d /opt/hostedtoolcache ]; then
307					if [ -L /opt/hostedtoolcache ]; then
308						if [ "$(readlink -f /opt/hostedtoolcache)" != "%s" ]; then
309							echo "Updating /opt/hostedtoolcache symlink to %s"
310							$SUDO rm -f /opt/hostedtoolcache
311							$SUDO mkdir -p /opt/hostedtoolcache
312							$SUDO mount --bind %s /opt/hostedtoolcache
313						else
314							echo "/opt/hostedtoolcache already correctly configured"
315						fi
316					else
317						echo "/opt/hostedtoolcache already exists as a directory"
318					fi
319				else
320					echo "Creating /opt/hostedtoolcache -> %s"
321					$SUDO mkdir -p /opt/hostedtoolcache
322					$SUDO mount --bind %s /opt/hostedtoolcache
323					if ! grep -q "^%s" /etc/fstab 2>/dev/null; then
324						echo "%s /opt/hostedtoolcache none defaults,bind 0 0" | $SUDO tee -a /etc/fstab
325					fi
326				fi`, linuxElevatePrelude, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix)
327				out, err := h.Run(hostedtoolcacheSetup)
328				if err != nil {
329					fmt.Fprintf(m.out(), "  %s: warning: failed to set up /opt/hostedtoolcache: %v\n", rc.Name, err)
330				} else {
331					fmt.Fprintf(m.out(), "  %s: /opt/hostedtoolcache configured\n", rc.Name)
332					if out != "" {
333						fmt.Fprintf(m.out(), "  %s: hostedtoolcache: %s\n", rc.Name, strings.TrimSpace(out))
334					}
335				}
336			}
337	
338			// Set up Docker DNS for agentic workflows.
339			// Agent containers (gh-aw) use host.docker.internal to reach the MCP Gateway running
340			// on the host network. Linux Docker does not resolve this by default; we configure
341			// dnsmasq as a local DNS resolver that answers host.docker.internal from the docker0
342			// bridge IP and forwards everything else upstream. This also ensures external DNS
343			// (model provider APIs, GitHub, etc.) works from inside agent containers.
344			fmt.Fprintf(m.out(), "  %s: setting up Docker DNS for agentic workflows...\n", rc.Name)
345			if err := m.setupAgenticDNS(h, rc.Name); err != nil {
346				fmt.Fprintf(m.out(), "  %s: warning: Docker DNS setup failed: %v\n", rc.Name, err)
347			}
348		}
349	
350		return nil
351	}
352	
353	func (m *Manager) startNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
354		return m.startNativeOnce(h, rc, instanceName, true)
355	}
356	
357	// startNativeOnce starts the runner and optionally detects a stale registration.
358	// When retryOnStale is true and the runner exits immediately with the stale-registration
359	// message, it clears local credentials, re-runs setupNative, and retries once.
360	func (m *Manager) startNativeOnce(h *host.Host, rc config.RunnerConfig, instanceName string, retryOnStale bool) error {
361		dir := h.RunnerDir(instanceName)
362	
363		ok, err := NativeRunnerConfigPresent(h, instanceName)
364		if err != nil {
365			return fmt.Errorf("checking runner install at %s: %w", dir, err)
366		}
367		if !ok {
368			fmt.Fprintf(m.out(), "  %s: not installed, running setup (this takes a few minutes)...\n", instanceName)
369			if setupErr := m.setupNative(h, rc); setupErr != nil {
370				return fmt.Errorf("auto-setup for %s: %w", instanceName, setupErr)
371			}
372		}
373	
374		if h.OS == "windows" {
375			out, err := h.RunShell(windowsNativeStartScript(h, instanceName))
376			if err != nil {
377				return err
378			}
379			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
380	
381			if retryOnStale {
382				fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
383				checkOut, _ := h.RunShell(windowsCheckStaleRegistration(h, instanceName))
384				if strings.TrimSpace(checkOut) == "stale" {
385					return m.handleStaleRegistration(h, rc, instanceName)
386				}
387			}
388			return nil
389		}
390	
391		// Unix (Linux / macOS)
392		cmd := fmt.Sprintf(
393			`cd %s; pid_file=".runner_pid"; `+
394				`if [ -f "$pid_file" ] && kill -0 "$(cat "$pid_file")" 2>/dev/null; then echo "already running"; exit 0; fi; `+
395				`nohup ./run.sh > runner.log 2>&1 & { echo $!; } > "$pid_file"; echo "started PID $!"`,
396			dir,
397		)
398		out, err := h.Run(cmd)
399		if err != nil {
400			return err
401		}
402		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
403	
404		if retryOnStale {
405			fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
406			checkCmd := fmt.Sprintf(
407				`sleep 5 && cd %s && pid=$(cat .runner_pid 2>/dev/null) && `+
408					`if [ -n "$pid" ] && kill -0 "$pid" 2>/dev/null; then echo ok; `+
409					`elif grep -q %q runner.log 2>/dev/null; then echo stale; `+
410					`else echo ok; fi`,
411				dir, staleRegistrationMsg,
412			)
413			checkOut, _ := h.Run(checkCmd)
414			if strings.TrimSpace(checkOut) == "stale" {
415				return m.handleStaleRegistration(h, rc, instanceName)
416			}
417		}
418		return nil
419	}
420	
421	func (m *Manager) handleStaleRegistration(h *host.Host, rc config.RunnerConfig, instanceName string) error {
422		fmt.Fprintf(m.out(), "  %s: registration expired on GitHub, re-configuring...\n", instanceName)
423		dir := h.RunnerDir(instanceName)
424	
425		if h.OS == "windows" {
426			h.RunShell(windowsDeleteRunnerConfig(h, instanceName))
427		} else {
428			h.Run(fmt.Sprintf("rm -f %s/.runner %s/.credentials %s/.credentials_rsaparams", dir, dir, dir))
429		}
430	
431		if err := m.setupNative(h, rc); err != nil {
432			return fmt.Errorf("re-configuring after stale registration: %w", err)
433		}
434	
435		return m.startNativeOnce(h, rc, instanceName, false)
436	}
